population.algorithm:
Multi-criteria greedy insertion using a weighted score balancing cost increase, time window urgency, and distance proximity, with prioritized fallback to least-loaded existing routes before creating new ones.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 1.0   // weight for cost increase
	const beta = 0.3    // weight for time window urgency
	const gamma = 0.7   // weight for distance proximity
	type candidate struct {
		assignIdx int
		score     float64
		ok        bool
		load      int
	}
	for jj := 0; jj < len(oris); jj++ {
		bestCandidate := candidate{-1, 1e100, false, 0}
		id := total_ship + jj
		ori := oris[jj]
		des := dess[jj]

		timeUrgency := 1.0
		if ori.TimeEnd > ori.TimeStart {
			windowWidth := ori.TimeEnd - ori.TimeStart
			currentWindowPos := ori.TimeStart
			if currentWindowPos < 0 {
				currentWindowPos = 0
			}
			normPos := float64(currentWindowPos) / float64(windowWidth)
			timeUrgency = 1.0 + normPos*beta
		}

		for idx := 0; idx < MAXASSIGNS; idx++ {
			if idx >= dispatch.AssignsLen {
				continue
			}
			oldCost := dispatch.Assigns[idx].Cost
			oldLoad := 0
			if assign := &dispatch.Assigns[idx]; assign.StationsLen > 0 {
				for s := 0; s < assign.StationsLen; s++ {
					oldLoad += assign.Stations[s].Load
				}
			}
			if dispatch.Assigns[idx].AddShip(id, ori, des) {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					baseScore := alpha * delta
					proximityBonus := 0.0
					if idx < dispatch.AssignsLen && dispatch.Assigns[idx].StationsLen > 0 {
						lastSta := dispatch.Assigns[idx].Stations[dispatch.Assigns[idx].StationsLen-1]
						distOri := cal_dis(lastSta, ori)
						distDes := cal_dis(des, lastSta)
						avgDist := (distOri + distDes) / 2.0
						proximityBonus = gamma * avgDist
					}
					totalScore := baseScore*timeUrgency - proximityBonus
					if !bestCandidate.ok || totalScore < bestCandidate.score ||
						(totalScore == bestCandidate.score && oldLoad < bestCandidate.load) {
						bestCandidate.assignIdx = idx
						bestCandidate.score = totalScore
						bestCandidate.ok = true
						bestCandidate.load = oldLoad
					}
				}
				dispatch.Assigns[idx].RemoveShip(id)
				dispatch.Assigns[idx].GenRoute()
			}
		}

		if bestCandidate.ok {
			idx := bestCandidate.assignIdx
			dispatch.Assigns[idx].AddShip(id, ori, des)
			dispatch.Assigns[idx].GenRoute()
		} else {
			fallbackUsed := false
			minLoadedIdx := -1
			minLoad := 1 << 30
			for idx := 0; idx < MAXASSIGNS; idx++ {
				if idx < dispatch.AssignsLen && dispatch.Assigns[idx].StationsLen == 0 {
					if dispatch.Assigns[idx].AddShip(id, ori, des) {
						dispatch.Assigns[idx].GenRoute()
						if dispatch.Assigns[idx].Cost >= 0 {
							fallbackUsed = true
							break
						}
						dispatch.Assigns[idx].RemoveShip(id)
						dispatch.Assigns[idx].GenRoute()
					}
				}
				if idx < dispatch.AssignsLen && dispatch.Assigns[idx].StationsLen > 0 {
					curLoad := 0
					for s := 0; s < dispatch.Assigns[idx].StationsLen; s++ {
						curLoad += dispatch.Assigns[idx].Stations[s].Load
					}
					if curLoad < minLoad {
						minLoad = curLoad
						minLoadedIdx = idx
					}
				}
			}
			if !fallbackUsed && minLoadedIdx >= 0 {
				if dispatch.Assigns[minLoadedIdx].AddShip(id, ori, des) {
					dispatch.Assigns[minLoadedIdx].GenRoute()
					if dispatch.Assigns[minLoadedIdx].Cost >= 0 {
						fallbackUsed = true
					} else {
						dispatch.Assigns[minLoadedIdx].RemoveShip(id)
						dispatch.Assigns[minLoadedIdx].GenRoute()
					}
				}
			}
			if !fallbackUsed {
				for idx := 0; idx < MAXASSIGNS; idx++ {
					if idx >= dispatch.AssignsLen {
						if dispatch.Assigns[idx].AddShip(id, ori, des) {
							dispatch.Assigns[idx].GenRoute()
							if dispatch.Assigns[idx].Cost >= 0 {
								dispatch.AssignsLen = idx + 1
								break
							}
							dispatch.Assigns[idx].RemoveShip(id)
							dispatch.Assigns[idx].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

