Iteratively attempt to insert each shipment into all existing routes sorted by current marginal cost increase, then fall back to appending to the next empty/new assign if no feasible insertion is found among non‑empty assigns.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		deltaCost float64
	}
	orderIdx := make([]int, len(oris))
	for i := range orderIdx {
		orderIdx[i] = i
	}
	rand.Shuffle(len(orderIdx), func(i, j int) {
		orderIdx[i], orderIdx[j] = orderIdx[j], orderIdx[i]
	})
	for _, oi := range orderIdx {
		ori := oris[oi]
		des := dess[oi]
		shipID := total_ship + oi
		bestCand := cand{-1, 0.0}
		found := false
		allIdx := make([]int, dispatch.AssignsLen+1)
		for i := 0; i < dispatch.AssignsLen; i++ {
			allIdx[i] = i
		}
		rand.Shuffle(dispatch.AssignsLen, func(i, j int) {
			allIdx[i], allIdx[j] = allIdx[j], allIdx[i]
		})
		newIdx := dispatch.AssignsLen
		if newIdx < MAXASSIGNS {
			allIdx[dispatch.AssignsLen] = newIdx
		} else {
			newIdx = -1
		}
		limitAll := dispatch.AssignsLen
		if newIdx >= 0 {
			limitAll++
		}
		for ai := 0; ai < limitAll; ai++ {
			aIdx := allIdx[ai]
			prevCost := dispatch.Assigns[aIdx].Cost
			if prevCost < 0 {
				continue
			}
			ok := dispatch.Assigns[aIdx].AddShip(shipID, ori, des)
			if !ok {
				dispatch.Assigns[aIdx].Cost = -1
				dispatch.Assigns[aIdx].RemoveShip(shipID)
				dispatch.Assigns[aIdx].GenRoute()
